							// not writable in our own directory? Skip
							break;
						}
					}
					self::$ml->pushHandler(new StreamHandler($logger_logfile, Logger::DEBUG));
					break;
				case 'mysql':
					self::$ml->pushHandler(new MysqlHandler(Logger::DEBUG));
					break;
			}
		}
		self::$is_initialized = true;
	}
